const items = $input.all();

// Allowed fields only
const allowedFields = [
  "image",
  "super_resolution_references"
];

// Normalize field names
function normalizeFieldName(name) {
  return name.toLowerCase().replace(/\s+/g, "_");
}

items.forEach(item => {
  const newJson = {};

  for (const key in item.json) {
    const normalizedKey = normalizeFieldName(key);
    if (!allowedFields.includes(normalizedKey)) continue;

    let value = item.json[key];

    // IMAGE: must be a non-empty string
    if (normalizedKey === "image") {
      if (typeof value !== "string" || value.trim() === "") {
        throw new Error("image must be a non-empty string");
      }
      newJson.image = value.trim();
      continue;
    }

    // SUPER RES REFS: ALWAYS ARRAY
    if (normalizedKey === "super_resolution_references") {
      let refs = [];

      if (typeof value === "string") {
        refs = value
          .split(",")
          .map(v => v.trim())
          .filter(Boolean);
      } else if (Array.isArray(value)) {
        refs = value.filter(Boolean);
      } else if (value) {
        refs = [value];
      }

      if (refs.length > 4) {
        throw new Error(
          `super_resolution_refs cannot contain more than 4 items (found ${refs.length})`
        );
      }

      newJson.super_resolution_refs = refs;
    }
  }

  // Ensure field exists even if user supplied nothing
  if (!newJson.super_resolution_refs) {
    newJson.super_resolution_refs = [];
  }

  item.json = newJson;
});

return items;
